(() => {'use strict';const budgets=Object.freeze({warningScore:600,largeScore:1500,maxCanvasObjects:2500,maxPhotosPerProject:1200});let worker=null,seq=0;const pending=new Map();function fallback(project){const r=window.DomusPremium?.complexity?.(project)||{score:0,level:'small'};return Promise.resolve({...r,source:'main-thread',budget:r.score>budgets.largeScore?'exceeded':r.score>budgets.warningScore?'warning':'ok'});}function ensure(){if(worker||typeof Worker==='undefined'||location.protocol==='file:')return worker;try{worker=new Worker('./workers/project-metrics-worker.js');worker.onmessage=(e)=>{const p=pending.get(e.data?.id);if(p){pending.delete(e.data.id);p.resolve(e.data.result);}};worker.onerror=()=>{worker?.terminate();worker=null;pending.forEach(p=>p.reject(new Error('Worker selhal.')));pending.clear();};}catch{worker=null;}return worker;}function analyze(project){const w=ensure();if(!w)return fallback(project);const id=`metrics-${Date.now()}-${++seq}`;return new Promise((resolve,reject)=>{pending.set(id,{resolve,reject});w.postMessage({id,project,budgets});}).catch(()=>fallback(project));}function idle(task,timeout=1200){return 'requestIdleCallback'in window?requestIdleCallback(task,{timeout}):setTimeout(()=>task({didTimeout:true,timeRemaining:()=>0}),1);}function virtualSlice(items,offset=0,limit=100){return Array.isArray(items)?items.slice(Math.max(0,offset),Math.max(0,offset)+Math.max(1,limit)):[];}window.DomusPerformance=Object.freeze({budgets,analyze,idle,virtualSlice});})();
